targets.query:
from(bucket: "phenohive")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r._measurement == "phenohive_measurements")
  |> filter(fn: (r) => r.station_id == "01")
  |> filter(fn: (r) => r._field =~ /_critical_quality_issue$/)
  |> map(fn: (r) => ({
      r with _value: if string(v: r._value) == "true" or string(v: r._value) == "1" then 1.0 else 0.0
    }))
  |> aggregateWindow(every: v.windowPeriod, fn: max, createEmpty: false)
  |> yield(name: "max")
